package org.jsoup.nodes;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.nodes.steps"
)
public class CucumberTest {
}

package org.jsoup.nodes.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Attribute;
import org.jsoup.nodes.Attributes;
import org.jsoup.nodes.Element;

import static org.junit.Assert.assertEquals;

public class StepDefs {
    private Element element;
    private Attribute attribute;

    @Given("a parsed HTML element {string}")
    public void a_parsed_html_element(String html) {
        element = Jsoup.parse(html).select("div").first();
    }

    @When("I retrieve the {string} Attribute object from the element's attributes")
    public void i_retrieve_the_attribute_from_the_element_attributes(String attributeName) {
        Attributes attributes = element.attributes();
        try {
            // Get the attribute by key
            attribute = attributes.get(attributeName);
        } catch (Exception e) {
            // Store the exception for later verification if needed
            System.out.println("Exception occurred: " + e.getMessage());
        }
    }

    @Then("the attribute key should be {string}")
    public void the_attribute_key_should_be(String expectedKey) {
        assertEquals(expectedKey, attribute.getKey());
    }

    @Then("the attribute value should be {string}")
    public void the_attribute_value_should_be(String expectedValue) {
        String actualValue = attribute.getValue();
        if (actualValue == null) {
            actualValue = "";
        }
        assertEquals(expectedValue, actualValue);
    }
}

